                    // =============================================
                    // Model detection and carousel functions
                    // =============================================

                    // Detect robot model (Matrix vs Standard) => Call this function AFTER initializeComponents()
                    async function initializeRobotModel() {
                        try {
                            // Check if MopPadLeftA exists (Matrix models)
                            const mopA = await getState('${prefix}.state.MopPadALeft');
                            isMatrixModel = mopA !== null && mopA !== undefined;
                            console.log(
                                'Robot model detected: ' +
                                (isMatrixModel ? 'Matrix (3 mops)' : 'Standard (1 mop)')
                            );
                            return isMatrixModel;
                        } catch (error) {
                            console.log('Model detection failed, assuming standard model');
                            isMatrixModel = false;
                            return false;
                        }
                    }

					// Function to check if detergent tracking is enabled
                    // Function to check if detergent tracking is enabled
                    async function initializeDetergentTracking() {
                        try {
                            // Check if detergent tracking state exists
                            const detergentTrackingState = await getState('${prefix}.state.detergent.EstimatedRefillDate');

                            // Check if the state exists and has a valid value (not null, undefined or empty)
                            isTrackingDetergents = detergentTrackingState !== null &&
                                                   detergentTrackingState !== undefined &&
                                                   detergentTrackingState !== '' &&
                                                   detergentTrackingState !== false;

                            console.log('Detergent tracking detected: ' + (isTrackingDetergents ? 'Enabled' : 'Disabled') +
                                       ' - Value: ' + detergentTrackingState);

                            return isTrackingDetergents;
                        } catch (error) {
                            console.log('Detergent tracking check failed, assuming disabled', error);
                            isTrackingDetergents = false;
                            return false;
                        }
                    }

                    // Load mop data for carousel display
                    async function loadMopDataForCarousel() {
                        try {
                            const mopInstances = ['A', 'B', 'C'];
                            for (const mopId of mopInstances) {
                                // Load percentage value
                                try {
                                    const percentage = await getState('${prefix}.state.MopPad' + mopId + 'Left') || 100;
                                    mopData[mopId].percentage = percentage;
                                } catch {
                                    mopData[mopId].percentage = 100;
                                }
                                // Load remaining time
                                try {
                                    const timeLeft = await getState('${prefix}.state.MopPad' + mopId + 'TimeLeft') || 0;
                                    mopData[mopId].timeLeft = timeLeft;
                                } catch {
                                    mopData[mopId].timeLeft = 0;
                                }
                                // Create SVG
                                createMopSVG(mopId, mopData[mopId].percentage);
                            }
                        } catch (error) {
                            console.error('Error while loading mop data:', error);
                        }
                    }

                    // Create SVG for specific mop in carousel
                    function createMopSVG(mopId, percentage) {
                        // Get the container element where the SVG will be inserted
                        const svgContainer = document.getElementById('mop-svg-' + mopId);
                        if (!svgContainer) return;
                        // For the carousel: Copy the SVG from the original component
                        const originalValueElement = document.getElementById('MopPadLeft-value');
                        if (!originalValueElement) return;
                        // Get the parent element of the original SVG
                        const svgParent = originalValueElement.previousElementSibling;
                        if (!svgParent) return;
                        // Get the original SVG element
                        const originalSvg = svgParent.querySelector('svg');
                        if (!originalSvg) return;
                        // Clone the original SVG
                        const clonedSvg = originalSvg.cloneNode(true);
                        // Adjust the IDs for this specific mop
                        clonedSvg.querySelectorAll('[id]').forEach(el => {
                            const id = el.getAttribute('id');
                            if (id) el.setAttribute('id', id + '-' + mopId); // Append mopId to each ID
                        });
                        // Scale the SVG (similar to other SVGs)
                        clonedSvg.removeAttribute('width');
                        clonedSvg.removeAttribute('height');
                        clonedSvg.style.width = '100%'; // Set width to 100%
                        clonedSvg.style.height = '100%'; // Set height to 100%
                        clonedSvg.style.maxWidth = '280px'; // Max width of 280px
                        clonedSvg.style.maxHeight = '280px'; // Max height of 280px
                        clonedSvg.style.minWidth = '150px'; // Min width of 150px
                        clonedSvg.style.minHeight = '150px'; // Max height of 150px
                        // Set color based on mopId
                        let baseColor;
                        switch (mopId) {
                            case 'A':
                                baseColor = '#0095fe';
                                break; // Blue
                            case 'B':
                                baseColor = '#8d8d8d';
                                break; // Gray
                            case 'C':
                                baseColor = '#ff9800';
                                break; // Orange
                            default:
                                baseColor = '#0095fe'; // Default to blue
                        }
                        clonedSvg.querySelectorAll('path').forEach(path => {
                            const currentFill = path.getAttribute('fill');
                            if (currentFill) {
                                path.setAttribute('fill', baseColor);
                            }
                        });
                        // Insert the cloned and updated SVG into the container
                        svgContainer.innerHTML = '';
                        svgContainer.appendChild(clonedSvg);
                        // Set the color based on the percentage after a slight delay
                        setTimeout(() => {
                            updateMoppPadPathColor(percentage, mopId);
                        }, 100);
                    }

                    // Initialize carousel controls and events
                    function initializeCarousel() {
                        const prevBtn = document.getElementById('prev-btn');
                        const nextBtn = document.getElementById('next-btn');
                        const indicators = document.querySelectorAll('.indicator');
                        const track = document.querySelector('.mop-carousel-track');
                        if (!prevBtn || !nextBtn || !track) return;
                        prevBtn.addEventListener('click', () => moveCarousel(-1));
                        nextBtn.addEventListener('click', () => moveCarousel(1));
                        indicators.forEach(indicator => {
                            indicator.addEventListener('click', () => {
                                const index = parseInt(indicator.getAttribute('data-index'));
                                goToSlide(index);
                            });
                        });
                    }

					// Move carousel by direction (-1 left, 1 right)
                    function moveCarousel(direction) {
                        const totalSlides = 3;
                        currentSlide = (currentSlide + direction + totalSlides) % totalSlides;
                        updateCarousel();
                        updateMopDetailInfo();
                    }

					// Go directly to specific slide
                    function goToSlide(index) {
                        currentSlide = index;
                        updateCarousel();
                        updateMopDetailInfo();
                    }

					// Update carousel visual position
                    function updateCarousel() {
                        const track = document.querySelector('.mop-carousel-track');
                        const indicators = document.querySelectorAll('.indicator');
                        const slides = document.querySelectorAll('.mop-slide');
                        if (!track) return;
                        const slideWidthPercentage = 45;
                        track.style.transform = 'translateX(-' + (currentSlide * slideWidthPercentage) + '%)';
                        slides.forEach((slide, index) => {
                            slide.classList.toggle('active', index === currentSlide);
                        });
                        indicators.forEach((indicator, index) => {
                            indicator.classList.toggle('active', index === currentSlide);
                        });
                        updateMopTitle();
                    }

                    // Start automatic rotation of carousel
                    function startAutoCarousel() {
                        if (carouselInterval) {
                            clearInterval(carouselInterval); // Stop previous interval
                        }
                        carouselInterval = setInterval(() => {
                            moveCarousel(1); // Go to the next slide
                        }, autoRotateSpeed);
                    }

                    // Stop automatic rotation
                    function stopAutoCarousel() {
                        if (carouselInterval) {
                            clearInterval(carouselInterval);
                            carouselInterval = null;
                        }
                    }

                    // Pause carousel on hover
                    function setupCarouselHoverPause() {
                        const carouselContainer = document.querySelector('.mop-carousel-container');
                        if (!carouselContainer) return;
                        carouselContainer.addEventListener('mouseenter', stopAutoCarousel);
                        carouselContainer.addEventListener('mouseleave', startAutoCarousel);
                    }

                    // Initialize auto-rotation after delay
                    function initAutoCarousel() {
                        // Wait for 2 seconds, then start
                        setTimeout(() => {
                            startAutoCarousel();
                            setupCarouselHoverPause();
                        }, 2000);
                    }

					// Update mop title in detail view
                    function updateMopTitle() {
                        const mopLetters = ['A', 'B', 'C'];
                        const currentMop = mopLetters[currentSlide];
                        const detailName = document.getElementById('component-detail-name');
                        if (detailName && isMatrixModel) {
                            const baseName = ComponentNames[UserLang]?.['MoppPad'] || 'Mop Pad';
                            detailName.textContent = baseName + ' ' + currentMop;
                        }
                    }

					// Update mop detail info for current slide
                    function updateMopDetailInfo() {
                        if (!isMatrixModel || !currentComponent || currentComponent.label !== 'MoppPad') return;
                        const mopLetters = ['A', 'B', 'C'];
                        const currentMop = mopLetters[currentSlide];
                        const mopInfo = mopData[currentMop];
                        if (!mopInfo) return;
                        // Update status text
                        const statusText = updateComponentStatusText('MoppPad', mopInfo.percentage, UserLang);
                        if (detailStatus) {
                            detailStatus.textContent = statusText.text;
                            detailStatus.style.color = statusText.color;
                            if (statusText.isYellow) {
                                detailStatus.classList.add("Component-with-outline");
                            } else {
                                detailStatus.classList.remove("Component-with-outline");
                            }
                        }
                        // Update percentage value
                        if (detailRemaining) {
                            const colorInfo = getComponentValueColor(mopInfo.percentage);
                            detailRemaining.textContent = mopInfo.percentage + '%';
                            detailRemaining.style.color = colorInfo.HSL;
                            if (colorInfo.isYellow) {
                                detailRemaining.classList.add("Component-with-outline");
                            } else {
                                detailRemaining.classList.remove("Component-with-outline");
                            }
                        }
                        // Update remaining time
                        if (detailTime) {
                            detailTime.textContent = mopInfo.timeLeft + 'h';
                            // Calculate color for time value
                            const maxHours = 200;
                            const ratio = Math.min(mopInfo.timeLeft / maxHours, 1);
                            const hue = ratio * 120;
                            detailTime.style.color = 'hsl(' + hue + ', 100%, 50%)';
                        }
                        // Adjust reset button text
                        if (detailReset) {
                            detailReset.innerHTML =
                                '<i class="fas fa-sync-alt"></i> ' +
                                (UserLang === "DE" ?
                                    ComponentNames[UserLang]['MoppPad'] + ' ' + currentMop + ' ' + ComponentDetailTexts[UserLang].resetText :
                                    ComponentDetailTexts[UserLang].resetText + ' ' + ComponentNames[UserLang]['MoppPad'] + ' ' + currentMop);
                        }
                    }

                    // Initialize component display elements
                    function initializeComponents() {
                        const componentList = document.getElementById('component-list');
                        if (!componentList) return;
                        components.forEach(component => {
                            const componentElement = document.createElement('div');
                            componentElement.className = 'compact-component';
                            componentElement.style = 'display: inline-flex; flex-direction: column; align-items: center; ' +
                                'min-width: 25px; padding: 1px; border-radius: 1px; ' +
                                'background: rgba(255,255,255,0.05); cursor: pointer; ' +
                                'transition: transform 0.2s ease;';
                            componentElement.innerHTML =
                                '<div style="margin-bottom: 3px; transition: transform 0.2s ease;">' + component.svg + '</div>' +
                                '<div id="' + component.id + '-value" style="font-size: 12px; font-weight: bold; margin-top: 3px;">-</div>' +
                                (component.timeId ?
                                    '<div id="' + component.timeId + '-value" style="font-size: 12px; margin-top: 2px; color: #aaa;">-</div>' :
                                    '');
                            // Hover effect
                            componentElement.addEventListener('mouseenter', () => {
                                componentElement.style.transform = 'scale(1.05)';
                                componentElement.querySelector('div').style.transform = 'scale(1.1)';
                            });
                            componentElement.addEventListener('mouseleave', () => {
                                componentElement.style.transform = 'scale(1)';
                                componentElement.querySelector('div').style.transform = 'scale(1)';
                            });
                            // Click event to show component details
                            componentElement.addEventListener('click', () => {
                                showComponentDetail(component);
                            });
                            componentList.appendChild(componentElement);
                        });
                    }

                    // Update all component statuses from states
                    function updateComponentStatus() {
                        let componentPercentages = {}; // An object to store the percentage for each component
                        components.forEach(component => {
                            // Special case for Water Tank
                            if (component.id === 'WaterTank') {
                                getState('${prefix}.state.water.PureWaterTank')
                                    .then(value => {
                                        updateComponentValue(component.label, component.id, value, '%');
                                        //updateWaterLevel(value);
                                    })
                                    .catch(err => console.error('Error with WaterTank:', err));
							} else if (component.label === 'MoppPad') {

								// Determine which mop should be shown in the main display
                                let activeComponentID = component.id;         // Default: 'MopPadLeft'
                                let activeComponentTime = component.timeId;   // Default: 'MopPadTimeLeft'

                                // Special handling for MopPad (supports multiple instances)
                                if (isMatrixModel) {
                                    // Matrix model: load all three instances (A, B, C) for carousel and detail view
                                    ['A', 'B', 'C'].forEach(mopId => {
                                        // Get percentage value for each instance
                                        getState('${prefix}.state.MopPad' + mopId + 'Left')
                                            .then(value => {
                                                const percentage = value || 100;
                                                mopData[mopId].percentage = percentage;

                                                // Update UI if the carousel is currently active
                                                if (currentComponent?.label === 'MoppPad' && isMatrixModel) {
                                                    updateMopInstanceUI(mopId, percentage);
                                                }
                                            }).catch(() => {
                                                mopData[mopId].percentage = 100;
                                            });

                                        // Get remaining time for each instance
                                        getState('${prefix}.state.MopPad' + mopId + 'TimeLeft')
                                            .then(value => {
                                                mopData[mopId].timeLeft = value || 0;
                                            }).catch(() => {
                                                mopData[mopId].timeLeft = 0;
                                            });
                                    });

                                    // For Matrix models: resolve the currently active mop type (A, B, or C)
                                    getState('${prefix}.state.ActiveMopType')
                                        .then(activeType => {
                                            if (activeType && activeType !== 'unknown') {
                                                activeComponentID = 'MopPad' + activeType + 'Left';
                                                activeComponentTime = 'MopPad' + activeType + 'TimeLeft';
                                                //console.log('[MopTracker] Showing active mop type ' + activeType + ' in main display');
                                            }

                                            // Load percentage for the selected/active component
                                            getState('${prefix}.state.' + activeComponentID)
                                                .then(value => {
                                                    componentPercentages[component.label] = value;
                                                    updateComponentValue(component.label, component.id, value, '%');
												}).catch(err => {
                                                    console.error('Error loading ' + activeComponentID + ':', err);
                                                });

                                            // Load remaining time for the selected/active component
                                            if (activeComponentTime) {
                                                getState('${prefix}.state.' + activeComponentTime)
                                                    .then(value => {
                                                        const percentage = componentPercentages[component.label] ?? 80;
                                                        const hours = value;
                                                        const maxTime = calculateMaxTime(hours, percentage);
                                                        updateComponentValue(component.label, component.timeId, hours, 'h', maxTime);
                                                    }).catch(err => {
                                                        console.error('Error loading ' + activeComponentTime + ':', err);
                                                    });
                                            }
                                        }).catch(err => {
                                            console.error('Error retrieving ActiveMopType:', err);
                                        });
                                } else {
                                    // Standard model: only a single MopPad instance
                                    getState('${prefix}.state.' + component.id)
                                        .then(value => {
                                            componentPercentages[component.label] = value;
                                            updateComponentValue(component.label, component.id, value, '%');
                                        }).catch(err =>
                                            console.error('Error loading ' + component.id + ':', err)
                                        );

                                    if (component.timeId) {
                                        getState('${prefix}.state.' + component.timeId)
                                            .then(value => {
                                                const percentage = componentPercentages[component.label] ?? 80;
                                                const hours = value;
                                                const maxTime = calculateMaxTime(hours, percentage);

                                                updateComponentValue(component.label, component.timeId, hours, 'h', maxTime);
                                            }).catch(err =>
                                                console.error('Error loading ' + component.timeId + ':', err)
                                            );
                                    }
                                }
                            } else {
                                // ALL OTHER COMPONENTS (MainBrush, SideBrush, Filter, Sensor, Detergent)
                                getState('${prefix}.state.' + component.id)
                                    .then(value => {
                                        componentPercentages[component.label] = value;
                                        updateComponentValue(component.label, component.id, value, '%');
                                    })
                                    .catch(err =>
                                        console.error('Error with ' + component.id + ':', err)
                                    );
                                if (component.timeId) {
                                    getState('${prefix}.state.' + component.timeId)
                                        .then(value => {
                                            const percentage =
                                                componentPercentages[component.label] ?? 80;
                                            const hours = value;
                                            const maxTime = calculateMaxTime(hours, percentage);
                                            updateComponentValue(component.label, component.timeId, hours, 'h', maxTime);
                                        })
                                        .catch(err =>
                                            console.error('Error with ' + component.timeId + ':', err)
                                        );
                                }
                            }
                        });
                        componentPercentages = {}; // Empty the componentPercentages object after each new update
                    }

                    // Update specific mop instance UI
                    function updateMopInstanceUI(mopId, percentage) {
                        // Update SVG color inside the carousel
                        const svgContainer = document.getElementById('mop-svg-' + mopId);
                        if (svgContainer) {
                            const leftMop = svgContainer.querySelector('[id*="mopppad2"]');
                            const rightMop = svgContainer.querySelector('[id*="mopppad1"]');
                            if (leftMop && rightMop) {
                                const hue = (percentage / 100) * 120;
                                const color = 'hsl(' + hue + ', 100%, 50%)';
                                leftMop.setAttribute('fill', color);
                                rightMop.setAttribute('fill', color);
                                // Highlight critical level
                                [leftMop, rightMop].forEach(path => {
                                    path.classList.toggle('critical-level', percentage < 5);
                                });
                            }
                        }
                        // If the carousel is currently visible, update detail information
                        if (isMatrixModel && currentComponent?.label === 'MoppPad') {
                            const mopLetters = ['A', 'B', 'C'];
                            const currentMop = mopLetters[currentSlide];
                            if (currentMop === mopId) {
                                updateMopDetailInfo();
                            }
                        }
                    }

					// Update component value display and color
                    function updateComponentValue(elementLabel, elementId, value, unit, maxTime = 24, updateSlider = false) {
                        const element = document.getElementById(elementId + '-value');
                        if (!element) return;
                        let displayValue, color, isYellowRange = false;
                        // Handling percentage unit
                        if (unit === '%') {
                            displayValue = Math.max(0, Math.min(100, value)) + '%';
                            const retCalculatedHSL = getComponentValueColor(value);
                            color = retCalculatedHSL.HSL;
                            isYellowRange = retCalculatedHSL.isYellow;
                        }
                        // Handling hours unit
                        else if (unit === 'h') {
                            displayValue = value + 'h';
                            const ratio = Math.min(value / maxTime, 1); // Normalize to 0�1 for up to 24h
                            const hue = ratio * 120;
                            color = color = 'hsl(' + hue + ', 100%, 50%)';
                            isYellowRange = hue >= 50 && hue <= 65;
                        }
                        // Default case for unknown unit
                        else {
                            displayValue = value ? value : '?';
                            color = value ? '#4CAF50' : '#F44336';
                        }
                        // Set the display value and apply the color
                        element.textContent = displayValue;
                        element.style.color = color;
                        if (isYellowRange) {
                            element.classList.add("Component-with-outline");
                        } else {
                            element.classList.remove("Component-with-outline");
                        }
                        updateSVGFillColor(elementLabel, value, unit);
                        if (elementLabel === 'Sensor' && unit === '%') {
                            updateSensorPathColor(value);
                        }
                        if (elementLabel === 'MoppPad' && unit === '%') {
                            updateMoppPadPathColor(value);
                        }
                        if (elementLabel === 'WaterTank' && unit === '%') {
                            updateWaterLevel(value);
                            getTankWaterLevel();
							if (updateSlider) {
						        const slider = document.getElementById('water-level-input');
						        const sliderLabel = document.getElementById('water-slider-value-label');
						        if (slider) slider.value = value;
						        if (sliderLabel) sliderLabel.textContent = value + '%';
						        waterSliderValue = value;
						        waterCurrentPercent = value;
						    }
                        }
                    }

					// Calculate color based on percentage value
                    function getComponentValueColor(value) {
                        // Clamp between 0�100
                        value = Math.max(0, Math.min(100, value));
                        const ratio = value / 100; // Normalize 0�1
                        const hue = ratio * 120; // 0 (red) to 120 (green)
                        const isYellowRange = hue >= 50 && hue <= 65;
                        return {
                            HSL: 'hsl(' + hue + ', 100%, 50%)',
                            isYellow: isYellowRange
                        };
                    }

					// Calculate max time based on hours and percentage
                    function calculateMaxTime(hours, percentage) {
                        return (hours / percentage) * 100;
                    }

                    // Update SVG fill color for component
                    function updateSVGFillColor(elementLabel, value, unit) {
                        if (typeof value !== 'number' || value < 0 || value > 100 || unit !== '%') {
                            return;
                        }
                        const elementConfig = {
                            'Detergent': {
                                id: 'detergent-SVG-level',
                                reverseHue: false
                            },
                            'Sidebrush': {
                                id: 'sidebrush-SVG-level',
                                reverseHue: false
                            },
                            'Filter': {
                                id: 'filter-SVG-level',
                                reverseHue: false
                            },
                            'MainBrush': {
                                id: 'mainbrush-SVG-level',
                                reverseHue: false
                            },
                        };
                        if (!elementConfig[elementLabel]) return;
                        // Get configuration for this element
                        const config = elementConfig[elementLabel];
                        const svgElement = document.getElementById(config.id);
                        if (!svgElement) {
                            return;
                        }
                        let hue = (value / 100) * 120; // Calculate hue (0-120 from red to green)
                        // Reverse hue if configured (green to red)
                        if (config.reverseHue) {
                            hue = 120 - hue;
                        }
                        const color = 'hsl(' + hue + ', 100%, 50%)';
                        svgElement.setAttribute('fill', color);
                        // Add class for extreme values
                        svgElement.classList.toggle('critical-level', value < 5);

						// Update Visibility Menu
						const visibilitySvgElement = document.getElementById('visibility-' + config.id);
						if (!visibilitySvgElement) {
                            return;
                        }
						visibilitySvgElement.setAttribute('fill', color);
                        // Add class for extreme values
                        visibilitySvgElement.classList.toggle('critical-level', value < 5);
                    }

					// Update sensor path animation colors
                    function updateSensorPathColor(value) {
                        // Select all sensor path elements
                        const sensorPaths = document.querySelectorAll('.Sensorpath');
                        if (typeof value !== 'number' || value < 0 || value > 100) {
                            return;
                        }
                        // Color calculation (Red for low values, Green for high values)
                        const hue = (value / 100) * 120; // HSL color value from 0 (red) to 120 (green)
                        const color = 'hsl(' + hue + ', 100%, 50%)';
                        // Temporarily disable animation while changing the color
                        sensorPaths.forEach(path => {
                            path.style.animation = 'none';
                            path.setAttribute('fill', color);
                            // Re-enable animation after a short delay
                            setTimeout(() => {
                                path.style.animation = '';
                            }, 50);
                        });
                        const svgElement = document.getElementById('sensor-SVG-level');
                        svgElement.classList.toggle('critical-level', value < 5); // Add class for extreme values
                    }

					// Update mop pad path colors
                    function updateMoppPadPathColor(value, mopId = null) {
                        // Validate parameters
                        if (typeof value !== 'number' || isNaN(value)) {
                            value = 100; // Default value
                        }
                        value = Math.max(0, Math.min(100, value)); // Clamp value between 0 and 100
                        // Calculate color
                        const hue = (value / 100) * 120;
                        const color = 'hsl(' + hue + ', 100%, 50%)';
                        const isCritical = value < 5;
                        if (mopId) {
                            // For carousel: Find specific container
                            updateMopPadInContainer(mopId, color, isCritical);
                        } else {
                            // For standard view: Find global paths
                            updateGlobalMopPad(color, isCritical);
                        }
                    }

					// Update mop pad in specific container
                    function updateMopPadInContainer(mopId, color, isCritical) {
                        const container = document.getElementById('mop-svg-' + mopId);
                        if (!container) {
                            console.warn('Container mop-svg-' + mopId + ' not found');
                            return;
                        }
                        // Try to find mop paths
                        const paths = container.querySelectorAll('path');
                        let mopPaths = [];
                        // Look for paths with specific IDs or classes
                        paths.forEach(path => {
                            const id = path.getAttribute('id') || '';
                            const className = path.getAttribute('class') || '';
                            if (id.includes('mopppad') || id.includes('SVG-level') ||
                                className.includes('Mop') || className.includes('Animation')) {
                                mopPaths.push(path);
                            }
                        });
                        // If not found, use the last two paths (typical for MopPad SVG)
                        if (mopPaths.length < 2 && paths.length >= 2) {
                            mopPaths = [paths[paths.length - 2], paths[paths.length - 1]];
                        }
                        // Set colors
                        mopPaths.forEach(path => {
                            path.setAttribute('fill', color);
                            if (isCritical) {
                                path.classList.add('critical-level');
                            } else {
                                path.classList.remove('critical-level');
                            }
                        });
                    }

					// Update global mop pad paths
                    function updateGlobalMopPad(color, isCritical) {
                        // For standard view: Look for all possible elements
                        const selectors = [
                            '#mopppad2-SVG-level',
                            '#mopppad1-SVG-level',
                            '[id*="mopppad2"]',
                            '[id*="mopppad1"]'
                        ];
                        selectors.forEach(selector => {
                            document.querySelectorAll(selector).forEach(element => {
                                element.setAttribute('fill', color);
                                if (isCritical) {
                                    element.classList.add('critical-level');
                                } else {
                                    element.classList.remove('critical-level');
                                }
                            });
                        });
                    }

					// Update water level visualization
                    function updateWaterLevel(level) {
                        // Convert the percentage value (0-100) to a Y offset (0 to 32)
                        const maxHigh = 0;
                        const minHigh = 32;
                        const y = minHigh + (maxHigh - minHigh) * (level / 100);
                        // Find all wave elements (also in the detail view)
                        document.querySelectorAll('#pureWaterTankWave').forEach(wave => {
                            wave.setAttribute("transform", 'translate(0, ' + y + ')');
                        });
                        // Change water color based on fill level
                        const waterFillElements = document.querySelectorAll('#pureWaterTankFill');
                        const hue = 120 * (level / 100); // Green (120) to Red (0)
                        waterFillElements.forEach(el => {
                            el.setAttribute('fill', 'hsl(' + hue + ', 100%, 50%)');
                        });
                    }

					// Get and display tank water level
                    function getTankWaterLevel() {
                        const element = document.getElementById('WaterTankLeft-value');
                        getState('${prefix}.state.water.Current')
                            .then(value => {
                                // Handle invalid values (null, undefined or NaN)
                                if (value === null || value === undefined || isNaN(value)) {
                                    console.warn('Invalid water level value received');
                                    element.textContent = '-- L';
                                    element.style.color = '#9E9E9E';
                                    return;
                                }
                                // Convert ml to liters
                                const liters = (value / 1000).toFixed(2);
                                let color;
                                const percentFull = (value / 4500) * 100;
                                const retCalculatedHSL = getComponentValueColor(percentFull);
                                color = retCalculatedHSL.HSL;
                                // Apply directly to UI elements
                                element.textContent = liters + ' L';
                                element.style.color = color;
                                if (retCalculatedHSL.isYellow) {
                                    element.classList.add("Component-with-outline");
                                } else {
                                    element.classList.remove("Component-with-outline");
                                }
                            })
                            .catch(err => {
                                console.error('Error fetching water level:', err);
                                element.textContent = '-- L';
                                element.style.color = '#9E9E9E';
                            });
                    }

// =============================================
// WATER TANK RESET
// =============================================

let waterSliderValue = 100;
let maxMl = null;

async function initWaterTank() {
    const slider = document.getElementById('water-level-input');
    const applyBtn = document.getElementById('component-detail-reset');
    const sliderLabel = document.getElementById('water-slider-value-label');

    if (!slider) return;

    // 1. Detect maximum tank capacity
    maxMl = await detectTankCapacity();

    // 2. Load and display initial water level
    const percent = await getState(prefix + '.state.water.PureWaterTank') || 100;
    waterSliderValue = percent;

    // Update component value with special slider handling
    updateComponentValue('WaterTank', 'WaterTankLeft', percent, '%', 24, true);

    // 3. Slider event
    slider.addEventListener('input', function(e) {
        const newPercent = parseInt(e.target.value);
        waterSliderValue = newPercent;
        if (sliderLabel) sliderLabel.textContent = newPercent + '%';

        // Preview only (visual update without saving)
        updateComponentValue('WaterTank', 'WaterTankLeft', newPercent, '%', 24, true);
    });

    console.log('[WaterTank] Initialized');
}

// Detect tank capacity
async function detectTankCapacity() {
    try {
        const capacityState = await getState(prefix + '.state.water.DetectedCapacity');
        if (capacityState !== null && capacityState !== undefined) return parseInt(capacityState);

        const maxSeenState = await getState(prefix + '.state.water.MaxSeen');
        if (maxSeenState !== null && maxSeenState !== undefined) return parseInt(maxSeenState);

        return 4500; // fallback default
    } catch (error) {
        console.error('[WaterTank] Capacity detection failed:', error);
        return 4500;
    }
}

// Persist water level permanently
async function applyWaterReset() {
    const newPercent = Math.min(100, Math.max(0, waterSliderValue));
    const newMl = Math.round((newPercent / 100) * maxMl);

    try {
        await setState(prefix + '.state.water.ResetPureWaterTank', newPercent);
        console.log('[WaterTank] Applied: ' + newPercent + '% (' + newMl + 'ml)');
    } catch (error) {
        console.error('[WaterTank] Apply failed:', error);
    }
}

                    // Initialize the detail view
