                        'water-check': 'Wasser prüfen',
                        'monitoring': 'Überwachen',
                        'monitoring-paused': 'Überwachung pausiert',
                        'error': 'Fehler',
                        'idle': 'Inaktiv',
                        'building': 'Bauen',
